const MEAL_GOALS = { cal: 2000, p: 150, c: 200, f: 65 };
const MACRO_BAR_CLASS = { Protein: 'bg-blue-500', Carbs: 'bg-orange-500', Fat: 'bg-yellow-400' };

function CalorieSummaryCard({ meals }) {
  const totals = meals.reduce((acc, m) => ({ cal: acc.cal + m.cal, p: acc.p + m.p, c: acc.c + m.c, f: acc.f + m.f }), { cal: 0, p: 0, c: 0, f: 0 });
  const macros = [
    { label: 'Protein', value: totals.p, goal: MEAL_GOALS.p },
    { label: 'Carbs', value: totals.c, goal: MEAL_GOALS.c },
    { label: 'Fat', value: totals.f, goal: MEAL_GOALS.f },
  ];
  return (
    <div data-dg-component="calorieSummaryCard" className="mx-4 mt-4 bg-white rounded-[20px] p-5 shadow-sm">
      <div className="flex justify-between items-center mb-2">
        <div>
          <span className="text-[28px] font-extrabold text-slate-900">{totals.cal}</span>
          <span className="text-[13px] text-slate-400 ml-1">/ {MEAL_GOALS.cal} kcal</span>
        </div>
        <div className="text-[13px] text-slate-500 bg-slate-100 rounded-full px-3 py-1">{MEAL_GOALS.cal - totals.cal} left</div>
      </div>
      <div className="h-2 bg-slate-100 rounded-full overflow-hidden mb-4">
        <div className="h-full bg-gradient-to-r from-blue-500 to-indigo-500 rounded-full" style={{ width: `${Math.min((totals.cal / MEAL_GOALS.cal) * 100, 100)}%` }} />
      </div>
      <div className="grid grid-cols-3 gap-3">
        {macros.map(m => (
          <div key={m.label} className="bg-slate-50 rounded-xl p-2.5">
            <div className="text-[11px] text-slate-400 mb-1">{m.label}</div>
            <div className="text-[15px] font-bold text-slate-900">{m.value}g</div>
            <div className="h-1 bg-slate-200 rounded-full mt-1 overflow-hidden">
              <div className={`h-full rounded-full ${MACRO_BAR_CLASS[m.label]}`} style={{ width: `${Math.min((m.value / m.goal) * 100, 100)}%` }} />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function MealList({ meals, onDelete }) {
  return (
    <div data-dg-component="mealList" className="mx-4 mt-4">
      <div className="text-[11px] font-bold text-slate-400 tracking-widest uppercase mb-2">Today's Meals</div>
      {meals.map(m => (
        <div key={m.id} className="bg-white rounded-[18px] p-4 mb-2.5 shadow-sm flex items-center gap-3">
          <div className="text-[28px]">{m.emoji}</div>
          <div className="flex-1 min-w-0">
            <div className="text-[14px] font-semibold text-slate-900 truncate">{m.name}</div>
            <div className="text-[12px] text-slate-400 mt-0.5">{m.time} · {m.cal} kcal</div>
          </div>
          <button onClick={() => onDelete(m.id)} className="text-slate-300 hover:text-red-400 transition-colors text-lg border-0 bg-transparent cursor-pointer">×</button>
        </div>
      ))}
    </div>
  );
}

function AddMealModal({ onAdd }) {
  const [show, setShow] = React.useState(false);
  const [name, setName] = React.useState('');
  const handle = () => { if (name.trim()) { onAdd(name.trim()); setName(''); setShow(false); } };
  return (
    <div data-dg-component="addMealModal">
      <button onClick={() => setShow(true)}
        className="fixed bottom-7 right-7 w-14 h-14 rounded-full bg-blue-500 shadow-lg text-white text-2xl border-0 cursor-pointer flex items-center justify-center">
        +
      </button>
      {show && (
        <div className="fixed inset-0 bg-black/40 flex items-end z-50" onClick={() => setShow(false)}>
          <div className="bg-white rounded-t-3xl px-5 pt-6 pb-8 w-full" onClick={e => e.stopPropagation()}>
            <div className="text-lg font-bold mb-4">Log a Meal</div>
            <input value={name} onChange={e => setName(e.target.value)} placeholder="e.g. Grilled salmon with rice"
              className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm outline-none focus:border-blue-400 mb-4" />
            <div className="flex gap-3">
              <button onClick={() => setShow(false)} className="flex-1 border border-slate-200 text-slate-500 rounded-xl py-3 text-sm font-semibold bg-transparent cursor-pointer">Cancel</button>
              <button onClick={handle} className="flex-1 bg-blue-500 text-white rounded-xl py-3 text-sm font-semibold border-0 cursor-pointer">Add Meal</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function App() {
  const [meals, setMeals] = React.useState([
    { id: 1, emoji: '🥣', name: 'Oatmeal with berries', cal: 320, p: 12, c: 52, f: 8, time: '8:00 AM' },
    { id: 2, emoji: '🥗', name: 'Grilled chicken salad', cal: 450, p: 42, c: 18, f: 16, time: '12:30 PM' },
    { id: 3, emoji: '🍦', name: 'Greek yogurt', cal: 150, p: 15, c: 12, f: 4, time: '3:00 PM' },
  ]);

  const handleAdd = (name) => setMeals(prev => [...prev, { id: Date.now(), emoji: '🍽️', name, cal: 200, p: 10, c: 25, f: 8, time: 'Now' }]);
  const handleDelete = (id) => setMeals(prev => prev.filter(m => m.id !== id));

  return (
    <div className="min-h-screen bg-slate-50 font-sans max-w-[390px] mx-auto pb-24">
      <div className="bg-white px-5 pt-4 pb-3 border-b border-slate-100">
        <div className="text-[11px] text-slate-400 mb-0.5">Monday, March 24</div>
        <div className="text-[22px] font-extrabold text-slate-900">Meal Log</div>
      </div>
      <CalorieSummaryCard meals={meals} />
      <MealList meals={meals} onDelete={handleDelete} />
      <AddMealModal onAdd={handleAdd} />
    </div>
  );
}

const WEEK_DATA = [
  { day: 'Mon', cal: 1820, goal: 2000 },
  { day: 'Tue', cal: 2100, goal: 2000 },
  { day: 'Wed', cal: 1650, goal: 2000 },
  { day: 'Thu', cal: 1920, goal: 2000 },
  { day: 'Fri', cal: 2200, goal: 2000 },
  { day: 'Sat', cal: 1500, goal: 2000 },
  { day: 'Sun', cal: 920, goal: 2000 },
];

function PeriodSelector({ period, onSelect }) {
  return (
    <div data-dg-component="periodSelector" className="bg-white px-5 pt-4 pb-3 border-b border-slate-100">
      <div className="text-[22px] font-bold text-slate-900">Progress</div>
      <div className="flex gap-2 mt-3">
        {['week', 'month', '3m'].map(p => (
          <button key={p} onClick={() => onSelect(p)}
            className={`px-4 py-1.5 rounded-full border-none cursor-pointer text-[13px] font-semibold ${period === p ? 'bg-blue-500 text-white' : 'bg-slate-100 text-slate-500'}`}>
            {p === 'week' ? 'Week' : p === 'month' ? 'Month' : '3 Months'}
          </button>
        ))}
      </div>
    </div>
  );
}

function CalorieIntakeChart({ data }) {
  const maxCal = Math.max(...data.map(d => d.cal));
  return (
    <div data-dg-component="calorieIntakeChart" className="mx-4 mt-4 bg-white rounded-[20px] p-5 shadow-sm">
      <div className="text-[15px] font-bold text-slate-900 mb-4">Calorie Intake</div>
      <div className="flex items-end gap-2 h-[100px]">
        {data.map(d => (
          <div key={d.day} className="flex-1 flex flex-col items-center gap-1">
            <div className={`w-full rounded-md flex items-end h-20 ${d.cal >= d.goal ? 'bg-amber-50' : 'bg-blue-50'}`}>
              <div className={`w-full rounded-md ${d.cal >= d.goal ? 'bg-amber-400' : 'bg-blue-500'}`} style={{ height: `${(d.cal / maxCal) * 80}px` }} />
            </div>
            <div className="text-[10px] text-slate-400">{d.day}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

function WeeklyStatsRow({ data }) {
  const avg = Math.round(data.reduce((s, d) => s + d.cal, 0) / data.length);
  const best = data.reduce((b, d) => d.cal > b.cal ? d : b, data[0]);
  const logged = data.filter(d => d.cal > 0).length;
  const stats = [
    { label: 'Avg Calories', value: avg.toLocaleString(), sub: 'kcal/day', emoji: '🔥' },
    { label: 'Best Day', value: best.day, sub: `${best.cal.toLocaleString()} kcal`, emoji: '⭐' },
    { label: 'Logged Days', value: `${logged}/7`, sub: 'this week', emoji: '📅' },
  ];
  return (
    <div data-dg-component="weeklyStatsRow" className="mx-4 mt-3 grid grid-cols-3 gap-2">
      {stats.map(s => (
        <div key={s.label} className="bg-white rounded-[18px] p-3 shadow-sm text-center">
          <div className="text-[18px]">{s.emoji}</div>
          <div className="text-[14px] font-bold text-slate-900 mt-1">{s.value}</div>
          <div className="text-[10px] text-slate-400 mt-0.5">{s.sub}</div>
        </div>
      ))}
    </div>
  );
}

function GoalsSection({ goals, activeGoal, onSelect }) {
  const barColors = ['bg-blue-500', 'bg-emerald-500', 'bg-orange-500'];
  return (
    <div data-dg-component="goalsSection" className="mx-4 mt-3 mb-8">
      <div className="text-[11px] font-bold text-slate-400 tracking-widest uppercase mb-2">Goals</div>
      {goals.map((g, i) => (
        <div key={g.id} onClick={() => onSelect(activeGoal === g.id ? null : g.id)}
          className="bg-white rounded-[18px] p-4 mb-2.5 shadow-sm cursor-pointer">
          <div className="flex justify-between items-center mb-2">
            <div className="text-[14px] font-semibold text-slate-900">{g.label}</div>
            <div className="text-[12px] text-slate-400">{g.detail}</div>
          </div>
          <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
            <div className={`h-full rounded-full ${barColors[i % barColors.length]}`} style={{ width: `${g.progress}%` }} />
          </div>
          {activeGoal === g.id && (
            <div className="mt-3 text-[12px] text-slate-500">{g.progress}% of target reached</div>
          )}
        </div>
      ))}
    </div>
  );
}

function App() {
  const [period, setPeriod] = React.useState('week');
  const [activeGoal, setActiveGoal] = React.useState(null);

  const goals = [
    { id: 1, label: 'Lose 5kg', progress: 62, detail: '3.1 kg lost' },
    { id: 2, label: 'Daily Protein', progress: 80, detail: '120g / 150g' },
    { id: 3, label: 'Calorie Deficit', progress: 45, detail: '5 of 7 days' },
  ];

  return (
    <div className="min-h-screen bg-slate-50 font-sans max-w-[390px] mx-auto pb-8">
      <PeriodSelector period={period} onSelect={setPeriod} />
      <CalorieIntakeChart data={WEEK_DATA} />
      <WeeklyStatsRow data={WEEK_DATA} />
      <GoalsSection goals={goals} activeGoal={activeGoal} onSelect={setActiveGoal} />
    </div>
  );
}
